def solve():
    s = input().strip()
    n = len(s)

    endings = ['00', '25', '50', '75']
    has_X = 'X' in s
    x_range = range(10) if has_X else range(1)

    count = 0

    for xv in x_range:
        # Replace X with xv
        t = list(s)
        for i in range(n):
            if t[i] == 'X':
                t[i] = str(xv)

        if n == 1:
            # Only divisible by 25 if the single digit is 0
            pos = t[0]
            if pos == '0':
                count += 1
            elif pos == '_':
                count += 1  # only '0' works
        else:
            for ending in endings:
                d1, d2 = ending[0], ending[1]
                # Check last two positions
                last2 = t[n-2:n]
                # Check compatibility
                ok = True
                for i, d in enumerate([d1, d2]):
                    ch = last2[i]
                    if ch != '_' and ch != d:
                        ok = False
                        break
                if not ok:
                    continue

                # Now count ways for positions 0..n-3
                # Build a temporary string with last two fixed
                u = t[:]
                u[n-2] = d1
                u[n-1] = d2

                # Count ways for remaining positions (0 to n-3)
                ways = 1
                for i in range(n-2):
                    if u[i] == '_':
                        if i == 0:
                            # leading position: can't be 0 unless n==1 (handled above)
                            # but if n>1, leading zero not allowed
                            ways *= 9
                        else:
                            ways *= 10
                    # else it's fixed, ways *= 1

                # Check leading zero: first char of u
                if n > 1:
                    first = u[0]
                    if first == '0':
                        # leading zero, skip
                        continue
                    # if first is '_', already handled by *9 above

                count += ways

    print(count)

solve()
